sql:
SELECT event_name, status
FROM event_planning
WHERE status = 'canceled';

SELECT COUNT(*) 
FROM event_planning 
WHERE status = 'canceled';

SELECT status, COUNT(*) AS event_count
FROM event_planning
GROUP BY status;

