External Knowledge:
- 'average levels of impact' refers to the average impact levels calculated from the 'impact_level' column in the 'weather_impact' table;
- 'weather-related canceled events' refers to events whose status is 'canceled' and whose cancellation reason contains the word 'weather'.

sql:
SELECT event_name, expected_attendees
FROM event_planning
WHERE status = 'planned' AND expected_attendees > 500;

SELECT MIN(expected_attendees) AS min_expected_attendees
FROM event_planning
WHERE status = 'canceled';

external_knowledge:
; The term 'weather impact' refers to the effects that weather conditions have on events; 
; 'outdoor events' are events that are held outside and can be affected by weather conditions; 
; 'levels of weather impact' can be high (severe weather conditions), medium (moderate weather conditions), or low (mild weather conditions).

sql:
SELECT operation_type, COUNT(*) as impact_count
FROM weather_impact
GROUP BY operation_type;

SELECT operation_type, impact_description
FROM weather_impact
WHERE impact_level = 'high';

SELECT forecast_date, confidence_level
FROM weather_forecasts
ORDER BY forecast_date DESC;
